Please suggest if the below solution can be modified in some way. Thanks [@shubham7811](https://leetcode.com/shubham7811)  for the insights.

```
a = [1,2,3]
b = [4,5]
queries = [[1,6], [0, 1, 2], [1,8]]

def solution(a, b, queries):
    hashmap = {}
    out = []

    for num in a:
        if num not in hashmap:
            hashmap[num] = 0
        hashmap[num] += 1

    for q in queries:
        if q[0] == 0:
            preval = a[q[1]]
            hashmap[preval] -= 1

            a[q[1]] += q[2]
            newval = a[q[1]]

            if newval not in hashmap:
                hashmap[newval] = 0
            hashmap[newval] += 1

        if q[0] == 1:
            count = 0
            for i, n in enumerate(b):
                other_num = q[1] - n
                if other_num in hashmap:
                    count += 1
            out.append(count)

    return out

solution(a, b, queries)
```
